fn write_serving_binary_v3_price_atoms_copy_from_pg_binary_reader<R: Read, W: Write>(
    reader: &mut R,
    writer: &mut CountingWriter<W>,
    target_format: ServingBinaryTargetCopyFormat,
    max_payload_bytes: usize,
    atom_key_bits: u8,
) -> io::Result<Value> {
    read_pg_binary_copy_header(reader)?;
    write_serving_binary_copy_header(writer, target_format)?;
    let mut state = ServingBinaryV3PriceAtomState::new(max_payload_bytes, atom_key_bits);
    while let Some(fields) = read_pg_binary_copy_row(reader, 9, "PTG2 v3 price atoms")? {
        let atom_key = pg_binary_nonnegative_i64(
            required_pg_binary_field(&fields, 0, "atom_key")?,
            "atom_key",
        )?;
        let negotiated_rate = fields[1]
            .as_deref()
            .map(pg_binary_negotiated_rate)
            .transpose()?;
        let mut attribute_keys =
            Vec::with_capacity(PTG2_SERVING_BINARY_PRICE_ATOM_V3_ATTRIBUTE_COUNT);
        for attribute_index in 0..PTG2_SERVING_BINARY_PRICE_ATOM_V3_ATTRIBUTE_COUNT {
            attribute_keys.push(pg_binary_optional_nonnegative_i64(
                fields[attribute_index + 2].as_deref(),
                &format!("attribute_key_{}", attribute_index + 1),
            )?);
        }
        state.push(
            writer,
            target_format,
            atom_key,
            negotiated_rate,
            attribute_keys,
        )?;
    }
    state.finish(writer, target_format)?;
    write_serving_binary_copy_trailer(writer, target_format)?;
    writer.flush()?;
    Ok(json!({
        "name": "serving_binary_v3_price_atoms",
        "format": PTG2_SERVING_BINARY_V3_FORMAT,
        "encoder_kind": PTG2_SERVING_BINARY_PRICE_ATOMS_V3_KIND,
        "artifact_kind": PTG2_SERVING_BINARY_PRICE_ATOMS_V3_KIND,
        "atom_count": state.expected_atom_key,
        "attribute_count": PTG2_SERVING_BINARY_PRICE_ATOM_V3_ATTRIBUTE_COUNT,
        "atom_key_bits": atom_key_bits,
        "atom_key_bytes": atom_key_bits / 8,
        "block_span": PTG2_SERVING_BINARY_PRICE_ATOMS_V3_BLOCK_SPAN,
        "block_count": state.block_stats.logical_block_count,
        "copy_record_count": state.block_stats.copy_record_count,
        "block_bytes": max_payload_bytes,
        "byte_count": writer.byte_count(),
        "source_copy_format": "postgres_binary",
        "target_copy_format": target_format.label(),
        "storage": state.block_stats.storage_summary(),
    }))
}

fn strict_v3_price_copy_stdio_usage() -> &'static str {
    "usage: ptg2_scanner --serving-binary-copy-from-key-copy-stdio \
<price_set_atom_memberships_v3|price_atoms_v3> <24|32>"
}

fn write_strict_v3_price_copy_from_pg_binary_stdio(
    kind: &str,
    options: &[String],
) -> io::Result<()> {
    if options.len() != 1 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            strict_v3_price_copy_stdio_usage(),
        ));
    }
    let atom_key_bits = serving_binary_v3_atom_key_bits(&options[0])?;
    let stdin = io::stdin();
    let stdout = io::stdout();
    let mut reader = BufReader::new(stdin.lock());
    let mut writer = CountingWriter::new(BufWriter::new(stdout.lock()));
    let target_format = ServingBinaryTargetCopyFormat::SharedBinary;
    let summary = match kind {
        PTG2_SERVING_BINARY_PRICE_SET_ATOM_MEMBERSHIPS_V3_KIND => {
            write_serving_binary_v3_memberships_copy_from_pg_binary_reader(
                &mut reader,
                &mut writer,
                target_format,
                serving_binary_block_bytes(),
                atom_key_bits,
            )?
        }
        PTG2_SERVING_BINARY_PRICE_ATOMS_V3_KIND => {
            write_serving_binary_v3_price_atoms_copy_from_pg_binary_reader(
                &mut reader,
                &mut writer,
                target_format,
                serving_binary_block_bytes(),
                atom_key_bits,
            )?
        }
        _ => {
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                strict_v3_price_copy_stdio_usage(),
            ));
        }
    };
    writeln!(io::stderr().lock(), "PTG2_SERVING_BINARY_COPY\t{summary}")
}

#[derive(Clone, Copy)]
struct SourceEncoding {
    count: u64,
    key_bits: u8,
    tagged_codec: TaggedServingRunCodec,
}

#[derive(Clone, Copy)]
struct AssignedV3EncoderOptions {
    grouped_payload_bytes: usize,
    hot_payload_bytes: usize,
    provider_code_sort_chunk_bytes: usize,
    source: SourceEncoding,
}

fn validate_source_encoding(source_count: u64, source_bits: u8) -> io::Result<()> {
    let expected_bits = source_key_bits(source_count)?;
    if source_bits != expected_bits {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            format!(
                "source_key_bits mismatch for source_count {source_count}: expected {expected_bits}, got {source_bits}"
            ),
        ));
    }
    Ok(())
}

fn append_source_encoding_header(
    payload: &mut Vec<u8>,
    format_version: u8,
    source_count: u64,
    source_bits: u8,
) -> io::Result<()> {
    validate_source_encoding(source_count, source_bits)?;
    payload.push(format_version);
    write_uvarint_to_vec(payload, source_count);
    payload.push(source_bits);
    Ok(())
}

fn encode_source_key_vector(
    source_keys: &[u32],
    source_count: u64,
    source_bits: u8,
) -> io::Result<Vec<u8>> {
    validate_source_encoding(source_count, source_bits)?;
    let total_bits = source_keys
        .len()
        .checked_mul(usize::from(source_bits))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "source provenance bit count overflows usize",
            )
        })?;
    let mut encoded = vec![0u8; total_bits.div_ceil(8)];
    let mut bit_offset = 0usize;
    for &source_key in source_keys {
        if u64::from(source_key) >= source_count {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                format!("source_key {source_key} is outside dense source_count {source_count}"),
            ));
        }
        for source_bit in 0..source_bits {
            if source_key & (1u32 << source_bit) != 0 {
                encoded[bit_offset / 8] |= 1u8 << (bit_offset % 8);
            }
            bit_offset += 1;
        }
    }
    Ok(encoded)
}

fn serving_binary_by_code_provider_shard_no(provider_set_key: i32) -> io::Result<i64> {
    if provider_set_key < 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "provider_set_key cannot be negative",
        ));
    }
    Ok(i64::from(provider_set_key) / PTG2_SERVING_BINARY_BY_CODE_PROVIDER_SHARD_SPAN)
}

fn serving_binary_by_code_provider_shard_block_key(
    code_key: i32,
    provider_set_key: i32,
) -> io::Result<i64> {
    if code_key < 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "code_key cannot be negative",
        ));
    }
    let shard_no = serving_binary_by_code_provider_shard_no(provider_set_key)?;
    if shard_no >= (1i64 << 31) {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "provider shard number exceeds its 31-bit block-key field",
        ));
    }
    Ok((i64::from(code_key) << 31) | shard_no)
}

fn encode_serving_by_code_group(
    provider_set_key: i32,
    previous_provider_set_key: i32,
    occurrence_count: usize,
    price_payload: &[u8],
    source_payload: &[u8],
) -> io::Result<Vec<u8>> {
    if provider_set_key < previous_provider_set_key {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "serving-binary grouped by-code rows must be ordered by provider_set_key within code_key",
        ));
    }
    if occurrence_count == 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "grouped by-code occurrence chunk cannot be empty",
        ));
    }
    let mut encoded = Vec::with_capacity(
        8usize
            .saturating_add(price_payload.len())
            .saturating_add(source_payload.len()),
    );
    write_uvarint_to_vec(
        &mut encoded,
        (provider_set_key - previous_provider_set_key) as u64,
    );
    write_uvarint_to_vec(&mut encoded, occurrence_count as u64);
    encoded.extend_from_slice(price_payload);
    encoded.extend_from_slice(source_payload);
    Ok(encoded)
}

fn serving_by_code_group_standalone_bytes(
    provider_set_key: i32,
    occurrence_count: usize,
    price_uvarint_bytes: usize,
    source_count: u64,
    source_bits: u8,
) -> io::Result<usize> {
    validate_source_encoding(source_count, source_bits)?;
    let provider_key = u64::try_from(provider_set_key).map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "provider_set_key cannot be negative",
        )
    })?;
    let source_bytes = occurrence_count
        .checked_mul(usize::from(source_bits))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code source bit count overflows usize",
            )
        })?
        .div_ceil(8);
    2usize
        .checked_add(uvarint_encoded_len(source_count))
        .and_then(|value| value.checked_add(uvarint_encoded_len(provider_key)))
        .and_then(|value| value.checked_add(uvarint_encoded_len(occurrence_count as u64)))
        .and_then(|value| value.checked_add(price_uvarint_bytes))
        .and_then(|value| value.checked_add(source_bytes))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code payload size overflows usize",
            )
        })
}

struct ServingBinaryByCodeProviderShardState {
    current_code: Option<i32>,
    current_block_key: Option<i64>,
    max_payload_bytes: usize,
    fragment_no: usize,
    current_entry_count: usize,
    previous_provider_set_key: i32,
    current_payload: Vec<u8>,
    current_provider_set_key: Option<i32>,
    current_occurrence_count: usize,
    current_price_payload: Vec<u8>,
    current_source_payload: Vec<u8>,
    current_group_is_continuation: bool,
    source_count: u64,
    source_bits: u8,
    copy_record_count: u64,
    logical_block_count: u64,
    group_count: u64,
    occurrence_chunk_count: u64,
    maximum_occurrences_buffered: usize,
}

impl ServingBinaryByCodeProviderShardState {
    fn new(max_payload_bytes: usize, source_count: u64, source_bits: u8) -> io::Result<Self> {
        if max_payload_bytes == 0 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                "by-code provider shard payload limit must be positive",
            ));
        }
        validate_source_encoding(source_count, source_bits)?;
        Ok(Self {
            current_code: None,
            current_block_key: None,
            max_payload_bytes,
            fragment_no: 0,
            current_entry_count: 0,
            previous_provider_set_key: 0,
            current_payload: Vec::with_capacity(max_payload_bytes.min(1024 * 1024)),
            current_provider_set_key: None,
            current_occurrence_count: 0,
            current_price_payload: Vec::new(),
            current_source_payload: Vec::new(),
            current_group_is_continuation: false,
            source_count,
            source_bits,
            copy_record_count: 0,
            logical_block_count: 0,
            group_count: 0,
            occurrence_chunk_count: 0,
            maximum_occurrences_buffered: 0,
        })
    }

    fn begin_logical_shard(&mut self, code_key: i32, block_key: i64) -> io::Result<()> {
        if self.current_entry_count != 0 || !self.current_payload.is_empty() {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "cannot begin a by-code provider shard before flushing the previous shard",
            ));
        }
        self.current_code = Some(code_key);
        self.current_block_key = Some(block_key);
        self.fragment_no = 0;
        self.previous_provider_set_key = 0;
        self.current_provider_set_key = None;
        self.current_group_is_continuation = false;
        self.logical_block_count = self.logical_block_count.saturating_add(1);
        Ok(())
    }
}

fn flush_serving_binary_by_code_provider_shard_fragment<W: Write>(
    writer: &mut W,
    state: &mut ServingBinaryByCodeProviderShardState,
    target_format: ServingBinaryTargetCopyFormat,
) -> io::Result<()> {
    if state.current_entry_count == 0 {
        return Ok(());
    }
    let block_key = state.current_block_key.ok_or_else(|| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "by-code provider shard payload has no logical block key",
        )
    })?;
    write_serving_binary_copy_record_with_i64_key_and_stats(
        writer,
        target_format,
        PTG2_SERVING_BINARY_BY_CODE_PROVIDER_SHARD_KIND,
        block_key,
        state.fragment_no,
        state.current_entry_count,
        &state.current_payload,
    )?;
    state.copy_record_count = state.copy_record_count.saturating_add(1);
    state.current_payload.clear();
    state.current_entry_count = 0;
    Ok(())
}

fn append_serving_binary_by_code_provider_group<W: Write>(
    writer: &mut W,
    state: &mut ServingBinaryByCodeProviderShardState,
    target_format: ServingBinaryTargetCopyFormat,
) -> io::Result<()> {
    let Some(provider_set_key) = state.current_provider_set_key else {
        state.current_occurrence_count = 0;
        state.current_price_payload.clear();
        state.current_source_payload.clear();
        return Ok(());
    };
    if state.current_occurrence_count == 0 {
        return Ok(());
    }
    let Some(_code_key) = state.current_code else {
        state.current_occurrence_count = 0;
        state.current_price_payload.clear();
        state.current_source_payload.clear();
        return Ok(());
    };
    if state.current_payload.is_empty() {
        append_source_encoding_header(
            &mut state.current_payload,
            PTG2_SERVING_BINARY_V3_GROUPED_FORMAT_VERSION,
            state.source_count,
            state.source_bits,
        )?;
    }
    let mut encoded = encode_serving_by_code_group(
        provider_set_key,
        state.previous_provider_set_key,
        state.current_occurrence_count,
        &state.current_price_payload,
        &state.current_source_payload,
    )?;
    if state.current_entry_count > 0
        && state.current_payload.len() + encoded.len() > state.max_payload_bytes
    {
        flush_serving_binary_by_code_provider_shard_fragment(writer, state, target_format)?;
        state.fragment_no = state.fragment_no.checked_add(1).ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "by-code provider shard fragment number overflows usize",
            )
        })?;
        state.previous_provider_set_key = 0;
        append_source_encoding_header(
            &mut state.current_payload,
            PTG2_SERVING_BINARY_V3_GROUPED_FORMAT_VERSION,
            state.source_count,
            state.source_bits,
        )?;
        encoded = encode_serving_by_code_group(
            provider_set_key,
            0,
            state.current_occurrence_count,
            &state.current_price_payload,
            &state.current_source_payload,
        )?;
    }
    if state.current_payload.len() + encoded.len() > state.max_payload_bytes {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "one grouped by-code occurrence chunk exceeds its payload limit",
        ));
    }
    state.current_payload.extend_from_slice(&encoded);
    state.current_entry_count += 1;
    state.previous_provider_set_key = provider_set_key;
    if !state.current_group_is_continuation {
        state.group_count = state.group_count.saturating_add(1);
    }
    state.occurrence_chunk_count = state.occurrence_chunk_count.saturating_add(1);
    state.current_occurrence_count = 0;
    state.current_price_payload.clear();
    state.current_source_payload.clear();
    Ok(())
}

fn push_serving_binary_by_code_occurrence<W: Write>(
    writer: &mut W,
    state: &mut ServingBinaryByCodeProviderShardState,
    target_format: ServingBinaryTargetCopyFormat,
    price_key: u32,
    source_key: u32,
) -> io::Result<()> {
    let provider_set_key = state.current_provider_set_key.ok_or_else(|| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "grouped by-code occurrence has no provider_set_key",
        )
    })?;
    if u64::from(source_key) >= state.source_count {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "source_key {source_key} is outside dense source_count {}",
                state.source_count
            ),
        ));
    }
    let next_count = state
        .current_occurrence_count
        .checked_add(1)
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code occurrence count overflows usize",
            )
        })?;
    let next_price_bytes = state
        .current_price_payload
        .len()
        .checked_add(uvarint_encoded_len(u64::from(price_key)))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code price byte count overflows usize",
            )
        })?;
    let next_standalone_bytes = serving_by_code_group_standalone_bytes(
        provider_set_key,
        next_count,
        next_price_bytes,
        state.source_count,
        state.source_bits,
    )?;
    let mut appended_count = next_count;
    if next_standalone_bytes > state.max_payload_bytes {
        if state.current_occurrence_count == 0 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "one grouped by-code occurrence cannot fit in the configured payload limit",
            ));
        }
        append_serving_binary_by_code_provider_group(writer, state, target_format)?;
        state.current_group_is_continuation = true;
        appended_count = 1;
        let single_occurrence_bytes = serving_by_code_group_standalone_bytes(
            provider_set_key,
            1,
            uvarint_encoded_len(u64::from(price_key)),
            state.source_count,
            state.source_bits,
        )?;
        if single_occurrence_bytes > state.max_payload_bytes {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "one grouped by-code occurrence cannot fit in the configured payload limit",
            ));
        }
    }
    write_uvarint_to_vec(&mut state.current_price_payload, u64::from(price_key));
    let source_bit_offset = state
        .current_occurrence_count
        .checked_mul(usize::from(state.source_bits))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code source bit offset overflows usize",
            )
        })?;
    let next_source_bits = appended_count
        .checked_mul(usize::from(state.source_bits))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code source bit count overflows usize",
            )
        })?;
    state
        .current_source_payload
        .resize(next_source_bits.div_ceil(8), 0);
    for source_bit in 0..state.source_bits {
        if source_key & (1u32 << source_bit) != 0 {
            let bit_offset = source_bit_offset + usize::from(source_bit);
            state.current_source_payload[bit_offset / 8] |= 1u8 << (bit_offset % 8);
        }
    }
    state.current_occurrence_count = appended_count;
    state.maximum_occurrences_buffered = state
        .maximum_occurrences_buffered
        .max(state.current_occurrence_count);
    Ok(())
}

type ServingBinaryV3ForwardPageCandidate = (u32, i32, u32, u64);

fn push_serving_binary_v3_forward_page_candidate(
    candidates: &mut BinaryHeap<ServingBinaryV3ForwardPageCandidate>,
    candidate: ServingBinaryV3ForwardPageCandidate,
) {
    if candidates.len() < PTG2_SERVING_BINARY_V3_PAGE_ROWS {
        candidates.push(candidate);
        return;
    }
    if candidates
        .peek()
        .is_some_and(|worst_candidate| candidate < *worst_candidate)
    {
        candidates.pop();
        candidates.push(candidate);
    }
}

fn write_serving_binary_v3_forward_page<W: Write>(
    writer: &mut W,
    target_format: ServingBinaryTargetCopyFormat,
    max_payload_bytes: usize,
    code_key: Option<i32>,
    candidates: &mut BinaryHeap<ServingBinaryV3ForwardPageCandidate>,
    block_stats: &mut ServingBinaryV3BlockStats,
    source: SourceEncoding,
) -> io::Result<()> {
    let Some(code_key) = code_key else {
        candidates.clear();
        return Ok(());
    };
    if candidates.is_empty() {
        return Ok(());
    }
    let mut ordered_candidates = candidates.drain().collect::<Vec<_>>();
    ordered_candidates.sort_unstable();
    let mut payload = Vec::with_capacity(4 + ordered_candidates.len() * 8);
    append_source_encoding_header(
        &mut payload,
        PTG2_SERVING_BINARY_PAGE_FORMAT_VERSION,
        source.count,
        source.key_bits,
    )?;
    write_uvarint_to_vec(&mut payload, ordered_candidates.len() as u64);
    for (price_key, provider_set_key, _, provider_count) in &ordered_candidates {
        write_uvarint_to_vec(&mut payload, *provider_set_key as u64);
        write_uvarint_to_vec(&mut payload, *provider_count);
        write_uvarint_to_vec(&mut payload, u64::from(*price_key));
    }
    payload.extend_from_slice(&encode_source_key_vector(
        &ordered_candidates
            .iter()
            .map(|(_, _, source_key, _)| *source_key)
            .collect::<Vec<_>>(),
        source.count,
        source.key_bits,
    )?);
    write_serving_binary_v3_logical_block(
        writer,
        target_format,
        max_payload_bytes,
        ServingBinaryV3LogicalBlock {
            artifact_kind: PTG2_SERVING_BINARY_BY_CODE_PRICE_PAGE_V4_KIND,
            block_key: code_key,
            entry_count: ordered_candidates.len(),
            payload: &payload,
        },
        block_stats,
    )
}

struct ServingBinaryV3ProviderProjection {
    provider_count: u64,
    total_row_count: u64,
    page_rows: Vec<(i32, u32, u32)>,
}

fn push_serving_binary_v3_provider_projection(
    projections: &mut BTreeMap<i32, ServingBinaryV3ProviderProjection>,
    provider_set_key: i32,
    provider_count: u64,
    code_key: i32,
    price_key: u32,
    source_key: u32,
) -> io::Result<()> {
    let projection =
        projections
            .entry(provider_set_key)
            .or_insert_with(|| ServingBinaryV3ProviderProjection {
                provider_count,
                total_row_count: 0,
                page_rows: Vec::with_capacity(1),
            });
    if projection.provider_count != provider_count {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "provider_count changed for provider_set_key {provider_set_key}: {} != {provider_count}",
                projection.provider_count
            ),
        ));
    }
    projection.total_row_count = projection.total_row_count.saturating_add(1);
    if projection.page_rows.len() < PTG2_SERVING_BINARY_V3_PAGE_ROWS {
        projection.page_rows.push((code_key, price_key, source_key));
    }
    Ok(())
}

fn serving_binary_provider_projection_count_payload(
    projections: &BTreeMap<i32, ServingBinaryV3ProviderProjection>,
) -> Vec<u8> {
    let mut payload = Vec::with_capacity(projections.len() * 2);
    let mut previous_provider_set_key = 0i32;
    for (provider_set_key, projection) in projections {
        write_uvarint_to_vec(
            &mut payload,
            (provider_set_key - previous_provider_set_key) as u64,
        );
        write_uvarint_to_vec(&mut payload, projection.provider_count);
        previous_provider_set_key = *provider_set_key;
    }
    payload
}

fn serving_binary_v3_provider_page_block_payload(
    block_key: i32,
    provider_entries: &[(i32, &ServingBinaryV3ProviderProjection)],
    source_count: u64,
    source_bits: u8,
) -> io::Result<Vec<u8>> {
    let block_start = i64::from(block_key) * PTG2_SERVING_BINARY_PROVIDER_SET_PAGE_V3_BLOCK_SPAN;
    let mut payload = Vec::new();
    append_source_encoding_header(
        &mut payload,
        PTG2_SERVING_BINARY_PAGE_FORMAT_VERSION,
        source_count,
        source_bits,
    )?;
    write_uvarint_to_vec(&mut payload, provider_entries.len() as u64);
    for (provider_set_key, projection) in provider_entries {
        let relative_key = i64::from(*provider_set_key) - block_start;
        if !(0..PTG2_SERVING_BINARY_PROVIDER_SET_PAGE_V3_BLOCK_SPAN).contains(&relative_key) {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 provider page key is outside its logical block",
            ));
        }
        write_uvarint_to_vec(&mut payload, relative_key as u64);
        write_uvarint_to_vec(&mut payload, projection.provider_count);
        write_uvarint_to_vec(&mut payload, projection.total_row_count);
        write_uvarint_to_vec(&mut payload, projection.page_rows.len() as u64);
        let mut previous_code_key = 0i32;
        let mut previous_pair = None;
        for (code_key, price_key, source_key) in &projection.page_rows {
            let pair = (*code_key, *price_key, *source_key);
            if previous_pair.is_some_and(|previous| pair < previous) {
                return Err(io::Error::new(
                    io::ErrorKind::InvalidData,
                    "PTG2 v3 provider page rows are not ordered",
                ));
            }
            write_uvarint_to_vec(&mut payload, (*code_key - previous_code_key) as u64);
            write_uvarint_to_vec(&mut payload, u64::from(*price_key));
            previous_code_key = *code_key;
            previous_pair = Some(pair);
        }
        payload.extend_from_slice(&encode_source_key_vector(
            &projection
                .page_rows
                .iter()
                .map(|(_, _, source_key)| *source_key)
                .collect::<Vec<_>>(),
            source_count,
            source_bits,
        )?);
    }
    Ok(payload)
}

fn write_serving_binary_v3_provider_pages<W: Write>(
    writer: &mut W,
    target_format: ServingBinaryTargetCopyFormat,
    max_payload_bytes: usize,
    projections: &BTreeMap<i32, ServingBinaryV3ProviderProjection>,
    block_stats: &mut ServingBinaryV3BlockStats,
    source_count: u64,
    source_bits: u8,
) -> io::Result<()> {
    let mut current_block_key = None;
    let mut provider_entries = Vec::new();
    for (provider_set_key, projection) in projections {
        let block_key = serving_binary_v3_block_key(
            i64::from(*provider_set_key),
            PTG2_SERVING_BINARY_PROVIDER_SET_PAGE_V3_BLOCK_SPAN,
            "provider_set_key",
        )?;
        if current_block_key.is_some_and(|current| current != block_key) {
            let payload = serving_binary_v3_provider_page_block_payload(
                current_block_key.unwrap_or_default(),
                &provider_entries,
                source_count,
                source_bits,
            )?;
            write_serving_binary_v3_logical_block(
                writer,
                target_format,
                max_payload_bytes,
                ServingBinaryV3LogicalBlock {
                    artifact_kind: PTG2_SERVING_BINARY_PROVIDER_SET_PAGE_V3_KIND,
                    block_key: current_block_key.unwrap_or_default(),
                    entry_count: provider_entries.len(),
                    payload: &payload,
                },
                block_stats,
            )?;
            provider_entries.clear();
        }
        current_block_key = Some(block_key);
        provider_entries.push((*provider_set_key, projection));
    }
    if let Some(block_key) = current_block_key {
        let payload = serving_binary_v3_provider_page_block_payload(
            block_key,
            &provider_entries,
            source_count,
            source_bits,
        )?;
        write_serving_binary_v3_logical_block(
            writer,
            target_format,
            max_payload_bytes,
            ServingBinaryV3LogicalBlock {
                artifact_kind: PTG2_SERVING_BINARY_PROVIDER_SET_PAGE_V3_KIND,
                block_key,
                entry_count: provider_entries.len(),
                payload: &payload,
            },
            block_stats,
        )?;
    }
    Ok(())
}

const SERVING_BINARY_V3_PROVIDER_CODE_MERGE_FAN_IN: usize = 64;

struct ServingBinaryV3ProviderCodeSpool {
    path: PathBuf,
    writer: BufWriter<File>,
    row_count: u64,
}

#[derive(Default)]
struct ServingBinaryV3ProviderCodeSortSummary {
    input_pair_count: u64,
    unique_pair_count: u64,
    spill_bytes: u64,
    scratch_read_bytes: u64,
    scratch_written_bytes: u64,
    chunk_count: u64,
    merge_pass_count: usize,
    maximum_merge_fan_in: usize,
    external_sort: bool,
}

impl ServingBinaryV3ProviderCodeSpool {
    fn new() -> io::Result<Self> {
        let base_dir = serving_binary_v3_spill_directory()?;
        let process_id = std::process::id();
        for attempt in 0..1000u32 {
            let path = base_dir.join(format!(
                "ptg2_v3_provider_codes_{process_id}_{:?}_{attempt}.pairs",
                thread::current().id()
            ));
            match OpenOptions::new().create_new(true).write(true).open(&path) {
                Ok(file) => {
                    return Ok(Self {
                        path,
                        writer: BufWriter::new(file),
                        row_count: 0,
                    });
                }
                Err(error) if error.kind() == io::ErrorKind::AlreadyExists => continue,
                Err(error) => return Err(error),
            }
        }
        Err(io::Error::new(
            io::ErrorKind::AlreadyExists,
            "unable to allocate PTG2 v3 provider-code spill file",
        ))
    }

    fn push(&mut self, provider_set_key: i32, code_key: i32) -> io::Result<()> {
        self.writer.write_all(&provider_set_key.to_be_bytes())?;
        self.writer.write_all(&code_key.to_be_bytes())?;
        self.row_count = self.row_count.saturating_add(1);
        Ok(())
    }

    fn emit_sorted_unique<W: Write>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
        state: &mut ServingBinaryV3ProviderCodeState,
        chunk_bytes: usize,
    ) -> io::Result<ServingBinaryV3ProviderCodeSortSummary> {
        self.writer.flush()?;
        let spill_bytes = self
            .row_count
            .saturating_mul(PROVIDER_CODE_PAIR_RECORD_BYTES as u64);
        if spill_bytes <= chunk_bytes as u64 {
            let unique_pair_count = self.emit_in_memory(writer, target_format, state)?;
            return Ok(ServingBinaryV3ProviderCodeSortSummary {
                input_pair_count: self.row_count,
                unique_pair_count,
                spill_bytes,
                scratch_read_bytes: spill_bytes,
                scratch_written_bytes: spill_bytes,
                chunk_count: u64::from(self.row_count > 0),
                merge_pass_count: 0,
                maximum_merge_fan_in: 0,
                external_sort: false,
            });
        }

        let mut temporary_files = ManifestPairTemporaryFiles::default();
        let sorted_path = manifest_pair_temporary_path(&self.path, "provider-code-sorted", 0);
        let temporary_directory = self.path.parent().unwrap_or_else(|| Path::new("."));
        let records_per_chunk = (chunk_bytes / PROVIDER_CODE_PAIR_RECORD_BYTES).max(1);
        let stats = external_sort_provider_code_pairs(
            std::slice::from_ref(&self.path),
            &sorted_path,
            temporary_directory,
            records_per_chunk,
        )?;
        temporary_files.track(sorted_path.clone());
        if stats.input_records != self.row_count || stats.input_bytes != spill_bytes {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "provider-code external sort input accounting mismatch",
            ));
        }
        let mut sorted_reader = BufReader::new(File::open(&sorted_path)?);
        let mut unique_pair_count = 0u64;
        while let Some(pair) = read_provider_code_pair(&mut sorted_reader)? {
            emit_provider_code_pair(writer, target_format, state, pair)?;
            unique_pair_count = unique_pair_count.saturating_add(1);
        }
        if unique_pair_count != stats.unique_records {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "provider-code external sort output accounting mismatch",
            ));
        }
        let merge_pass_count = provider_code_merge_pass_count(stats.chunk_count);
        Ok(ServingBinaryV3ProviderCodeSortSummary {
            input_pair_count: self.row_count,
            unique_pair_count,
            spill_bytes,
            scratch_read_bytes: stats
                .input_bytes
                .saturating_add(stats.spill_bytes)
                .saturating_add(stats.output_bytes),
            scratch_written_bytes: spill_bytes
                .saturating_add(stats.spill_bytes)
                .saturating_add(stats.output_bytes),
            chunk_count: stats.chunk_count,
            merge_pass_count,
            maximum_merge_fan_in: usize::try_from(stats.chunk_count)
                .unwrap_or(usize::MAX)
                .min(SERVING_BINARY_V3_PROVIDER_CODE_MERGE_FAN_IN),
            external_sort: true,
        })
    }

    fn emit_in_memory<W: Write>(
        &self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
        state: &mut ServingBinaryV3ProviderCodeState,
    ) -> io::Result<u64> {
        let mut reader = BufReader::new(File::open(&self.path)?);
        let pair_capacity = usize::try_from(self.row_count).map_err(|_| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "provider-code pair count exceeds usize",
            )
        })?;
        let mut pairs = Vec::new();
        pairs.try_reserve_exact(pair_capacity).map_err(|error| {
            io::Error::new(
                io::ErrorKind::OutOfMemory,
                format!(
                    "unable to reserve {} bytes for provider-code sorting: {error}",
                    pair_capacity.saturating_mul(PROVIDER_CODE_PAIR_RECORD_BYTES)
                ),
            )
        })?;
        while let Some(pair) = read_provider_code_pair(&mut reader)? {
            pairs.push(pair);
        }
        pairs.sort_unstable();
        pairs.dedup();
        for pair in &pairs {
            emit_provider_code_pair(writer, target_format, state, *pair)?;
        }
        Ok(pairs.len() as u64)
    }
}

impl Drop for ServingBinaryV3ProviderCodeSpool {
    fn drop(&mut self) {
        let _ = std::fs::remove_file(&self.path);
    }
}

fn read_provider_code_pair<R: Read>(
    reader: &mut R,
) -> io::Result<Option<[u8; PROVIDER_CODE_PAIR_RECORD_BYTES]>> {
    let mut pair = [0u8; PROVIDER_CODE_PAIR_RECORD_BYTES];
    let mut offset = 0usize;
    while offset < pair.len() {
        let bytes_read = reader.read(&mut pair[offset..])?;
        if bytes_read == 0 {
            if offset == 0 {
                return Ok(None);
            }
            return Err(io::Error::new(
                io::ErrorKind::UnexpectedEof,
                "PTG2 v3 provider-code spool ended with a partial record",
            ));
        }
        offset += bytes_read;
    }
    Ok(Some(pair))
}

fn emit_provider_code_pair<W: Write>(
    writer: &mut W,
    target_format: ServingBinaryTargetCopyFormat,
    state: &mut ServingBinaryV3ProviderCodeState,
    pair: [u8; PROVIDER_CODE_PAIR_RECORD_BYTES],
) -> io::Result<()> {
    let provider_set_key = i32::from_be_bytes(pair[..4].try_into().map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "provider-code provider key is invalid",
        )
    })?);
    let code_key = i32::from_be_bytes(pair[4..].try_into().map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "provider-code code key is invalid",
        )
    })?);
    state.push(
        writer,
        target_format,
        i64::from(provider_set_key),
        i64::from(code_key),
    )
}

fn provider_code_merge_pass_count(mut chunk_count: u64) -> usize {
    if chunk_count == 0 {
        return 0;
    }
    let mut pass_count = 1usize;
    while chunk_count >= SERVING_BINARY_V3_PROVIDER_CODE_MERGE_FAN_IN as u64 {
        chunk_count = chunk_count.div_ceil(SERVING_BINARY_V3_PROVIDER_CODE_MERGE_FAN_IN as u64);
        pass_count = pass_count.saturating_add(1);
    }
    pass_count
}

#[cfg(test)]
struct PgBinaryAssignedV3RowSource<'a, R> {
    reader: &'a mut R,
    field_count: i16,
    source_field_present: bool,
}

#[cfg(test)]
impl<'a, R: Read> PgBinaryAssignedV3RowSource<'a, R> {
    fn new(reader: &'a mut R, source_field_present: bool) -> io::Result<Self> {
        read_pg_binary_copy_header(reader)?;
        Ok(Self {
            reader,
            field_count: if source_field_present { 5 } else { 4 },
            source_field_present,
        })
    }
}

#[cfg(test)]
impl<R: Read> AssignedV3RowSource for PgBinaryAssignedV3RowSource<'_, R> {
    fn next_row(&mut self) -> io::Result<Option<AssignedV3Row>> {
        let Some(fields) =
            read_pg_binary_copy_row(self.reader, self.field_count, "PTG2 v3 assigned by-code")?
        else {
            return Ok(None);
        };
        let code_key = pg_binary_nonnegative_i32(
            required_pg_binary_field(&fields, 0, "code_key")?,
            "code_key",
        )?;
        let provider_set_key = pg_binary_nonnegative_i32(
            required_pg_binary_field(&fields, 1, "provider_set_key")?,
            "provider_set_key",
        )?;
        let provider_count = pg_binary_u64(
            required_pg_binary_field(&fields, 2, "provider_count")?,
            "provider_count",
        )?;
        let price_key = u32::try_from(pg_binary_nonnegative_i64(
            required_pg_binary_field(&fields, 3, "price_key")?,
            "price_key",
        )?)
        .map_err(|_| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 assigned price_key exceeds u32",
            )
        })?;
        let source_key = if self.source_field_present {
            u32::try_from(pg_binary_nonnegative_i64(
                required_pg_binary_field(&fields, 4, "source_key")?,
                "source_key",
            )?)
            .map_err(|_| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "PTG2 v3 assigned source_key exceeds u32",
                )
            })?
        } else {
            0
        };
        Ok(Some(AssignedV3Row {
            code_key,
            provider_set_key,
            provider_count,
            price_key,
            source_key,
        }))
    }

    fn source_copy_format(&self) -> &'static str {
        "postgres_binary"
    }
}

#[cfg(test)]
